      {/* Message Details Modal */}
      <Modal
        title={t('adminDashboard.contact.messageDetails')}
        visible={messageModalVisible}
        onCancel={() => setMessageModalVisible(false)}
        width={700}
        footer={[
          <Button key="close" onClick={() => setMessageModalVisible(false)}>
            {t('actions.close')}
